# Printing elements
def print_elements(elements: iter):
    print(Fore.CYAN)
    print(highlight(json.dumps(elements, indent=4), lexers.JsonLexer(), formatters.Terminal256Formatter()))
    print(Fore.WHITE)
    
    return
